import{_ as e,c as t,o as n,ae as r}from"./chunks/framework.BvcDoAct.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/RockInOnJapan_BF/0_INTRO.md","filePath":"zh-cn/RockInOnJapan_BF/0_INTRO.md"}'),p={name:"zh-cn/RockInOnJapan_BF/0_INTRO.md"};function o(_,a,c,s,T,i){return n(),t("div",null,[...a[0]||(a[0]=[r('<h2 id="在不断进化的日子深处-所铭刻下的各自信念——" tabindex="-1">在不断进化的日子深处，所铭刻下的各自信念—— <a class="header-anchor" href="#在不断进化的日子深处-所铭刻下的各自信念——" aria-label="Permalink to &quot;在不断进化的日子深处，所铭刻下的各自信念——&quot;">​</a></h2><h2 id="由一路追踪be-first的japan呈现-从过去延伸至未来的长线访谈" tabindex="-1">由一路追踪BE:FIRST的JAPAN呈现，从过去延伸至未来的长线访谈 <a class="header-anchor" href="#由一路追踪be-first的japan呈现-从过去延伸至未来的长线访谈" aria-label="Permalink to &quot;由一路追踪BE:FIRST的JAPAN呈现，从过去延伸至未来的长线访谈&quot;">​</a></h2><p>2021年，从选秀项目「THE FIRST」中诞生的BE:FIRST，于11月3日迎来了主流出道4周年。而在此之前的10月29日，他们发行了组合首张精选专辑《BE:ST》。出道4年便推出精选专辑——对于一般艺人来说或许显得稍早，但当你凝视曲目列表中超过30首的作品时，便会心生认同。这里所铭刻的多彩且多样的乐曲，正是他们密度极高的岁月足迹，也是不断进化的证明。</p><p>4年前，在事务所社长兼制作人SKY-HI的引领下启程的BE:FIRST，如今已手握健康的自由与旺盛的好奇心，凭借自身的步伐不断迈向更高的台阶。从巨蛋巡演到世界巡演，再到体育场级别演出，演出规模的持续扩大正是最直接的证明。而在这一切背后，更重要的是成员们亲自参与音乐创作，亲手捕捉并打造“当下所需要的声音”的这段历程。《让我们去证明什么才是最强》——这是首张专辑《BE:1》主打曲〈Scream〉中的一句歌词。正如这句宣言所言，他们始终在不断更新并亲自证明“最强”，一路走到了今天。</p><p>在《BE:ST》发行这一时间点，制作本杂志的BE:FIRST特辑时，我们思考的是：希望能够解开，在这段耀眼历史背后，每一位成员内心究竟在思考些什么。</p><p>作为“最强的进化集体”BE:FIRST继续前行的过程中，他们发生了怎样的改变，又在怎样的层面上始终未变——事实上，本杂志早在《BE:1》发行后的2022年秋起，用约半年的时间，对成员展开了个人专访连载。本次别册特辑，正是在梳理当时每个人所说过的话的同时，再次尝试触及流淌在他们内心深处的信念（此外，在各篇访谈页面中，也重新刊载了3年前文章中的旧照片，希望读者也能关注他们的变化）。</p><p>为什么BE:FIRST之所以成为BE:FIRST？为什么他们能够持续证明着“最强”？</p><p>我们相信，这是一篇能够触及其真髓的、独一无二的特集。 <br><br></p><p>（安田季那子）</p><p>采访＝小川智宏 摄影＝大野隼男</p>',10)])])}const d=e(p,[["render",o]]);export{S as __pageData,d as default};
